def predict_next_frame(frame, action, xy=None):
    """
    Predict the next frame for the grid game.

    Observations show that ACTION5 changes exactly one cell on row 53 from
    value 2 to value 3. The column chosen is the first occurrence of a 2 that
    is **not** part of a left‑hand run of consecutive 2's (i.e. the leftmost
    2 whose immediate left neighbour is not also a 2, or the very first 2 if
    it stands alone). All other actions leave the board unchanged.
    """
    # copy the frame so we don't mutate the input
    new_frame = [row[:] for row in frame]

    if action == "ACTION5":
        target_row = 53
        if 0 <= target_row < len(new_frame):
            row_vals = new_frame[target_row]
            col_to_change = None
            for c, v in enumerate(row_vals):
                if v == 2:
                    # left neighbour is not a 2 (or this is column 0)
                    if c == 0 or row_vals[c - 1] != 2:
                        col_to_change = c
                        break
            # fallback: if every 2 is part of a run, just change the first 2
            if col_to_change is None:
                try:
                    col_to_change = row_vals.index(2)
                except ValueError:
                    col_to_change = None

            if col_to_change is not None:
                new_frame[target_row][col_to_change] = 3

    # other actions (including ACTION6) do not modify the board in the observed data
    return new_frame
